# Airflow Celery workers — a SEPARATE, horizontally scalable container app. This is the
# point of CeleryExecutor: each worker replica gets its own 2 vCPU / 4 GiB (the per-replica
# Consumption cap), and we run several — lifting the single-LocalExecutor ceiling that
# throttled task throughput. Workers pull tasks from the Redis broker, execute, and write
# results to the Postgres result backend. No ingress (workers don't serve traffic).
resource "azurerm_container_app" "airflow_worker" {
  name                         = "dataq-harness-airflow-worker"
  container_app_environment_id = azurerm_container_app_environment.harness.id
  resource_group_name          = data.azurerm_resource_group.dataq.name
  revision_mode                = "Single"

  # The metadata DB must be migrated (by the main app's init container) before workers
  # can run tasks; ordering the worker after the scheduler app makes that the common case.
  depends_on = [azurerm_container_app.airflow]

  identity {
    type = "SystemAssigned"
  }

  registry {
    server               = azurerm_container_registry.harness.login_server
    username             = azurerm_container_registry.harness.admin_username
    password_secret_name = "acr-password"
  }

  # Workers need the same secrets the tasks touch (no webserver/admin secrets).
  secret {
    name  = "acr-password"
    value = azurerm_container_registry.harness.admin_password
  }
  secret {
    name  = "adls-conn"
    value = azurerm_storage_account.landing.primary_connection_string
  }
  secret {
    name  = "snowflake-password"
    value = var.snowflake_password
  }
  secret {
    name  = "databricks-token"
    value = var.databricks_token
  }
  secret {
    name  = "celery-result-backend"
    value = local.celery_result_backend
  }
  secret {
    name  = "pg-conn"
    value = local.airflow_pg_conn
  }
  secret {
    name  = "fernet-key"
    value = local.airflow_fernet_key
  }
  # Inherited via the shared env (AIRFLOW__WEBSERVER__SECRET_KEY) even though the worker
  # serves no web UI — must exist as a secret ref.
  secret {
    name  = "webserver-secret"
    value = random_password.airflow_webserver_secret.result
  }

  template {
    min_replicas = 2 # two always-on workers; raise max for burst
    max_replicas = 4

    container {
      name   = "worker"
      image  = local.airflow_image
      cpu    = 2.0 # worker-only app → can take the full per-replica cap
      memory = "4Gi"
      args   = ["celery", "worker"]
      dynamic "env" {
        for_each = local.airflow_env
        content {
          name        = env.value.name
          value       = lookup(env.value, "value", null)
          secret_name = lookup(env.value, "secret_name", null)
        }
      }
    }
  }

  tags = local.common_tags
}

